const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { GraphQLObjectType, GraphQLSchema, GraphQLString, GraphQLInt, GraphQLList, GraphQLNonNull } = require('graphql');
const { Pool } = require('pg');
const rateLimit = require('express-rate-limit');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');

const app = express();

const pool = new Pool({
  host: process.env.DB_HOST,
  port: parseInt(process.env.DB_PORT || '5432', 10),
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  ssl: process.env.DB_SSL === 'true' ? { rejectUnauthorized: true } : false,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP'
});

app.use(limiter);

const AuthorType = new GraphQLObjectType({
  name: 'Author',
  fields: {
    id: { type: new GraphQLNonNull(GraphQLInt) },
    name: { type: new GraphQLNonNull(GraphQLString) },
    email: { type: new GraphQLNonNull(GraphQLString) }
  }
});

const PostType = new GraphQLObjectType({
  name: 'Post',
  fields: {
    id: { type: new GraphQLNonNull(GraphQLInt) },
    title: { type: new GraphQLNonNull(GraphQLString) },
    content: { type: new GraphQLNonNull(GraphQLString) },
    author_id: { type: new GraphQLNonNull(GraphQLInt) },
    author: {
      type: AuthorType,
      resolve: async (parent) => {
        const result = await pool.query(
          'SELECT id, name, email FROM authors WHERE id = $1',
          [parent.author_id]
        );
        return result.rows[0] || null;
      }
    }
  }
});

const RootQuery = new GraphQLObjectType({
  name: 'RootQueryType',
  fields: {
    post: {
      type: PostType,
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) }
      },
      resolve: async (parent, args) => {
        if (!Number.isInteger(args.id) || args.id < 1) {
          throw new Error('Invalid post ID');
        }
        const result = await pool.query(
          'SELECT id, title, content, author_id FROM posts WHERE id = $1',
          [args.id]
        );
        return result.rows[0] || null;
      }
    },
    posts: {
      type: new GraphQLList(PostType),
      args: {
        limit: { 
          type: GraphQLInt,
          defaultValue: 10
        },
        offset: {
          type: GraphQLInt,
          defaultValue: 0
        }
      },
      resolve: async (parent, args) => {
        const limit = Math.min(Math.max(1, args.limit || 10), 100);
        const offset = Math.max(0, args.offset || 0);
        
        const result = await pool.query(
          'SELECT id, title, content, author_id FROM posts ORDER BY id LIMIT $1 OFFSET $2',
          [limit, offset]
        );
        return result.rows;
      }
    },
    author: {
      type: AuthorType,
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) }
      },
      resolve: async (parent, args) => {
        if (!Number.isInteger(args.id) || args.id < 1) {
          throw new Error('Invalid author ID');
        }
        const result = await pool.query(
          'SELECT id, name, email FROM authors WHERE id = $1',
          [args.id]
        );
        return result.rows[0] || null;
      }
    }
  }
});

const schema = new GraphQLSchema({
  query: RootQuery
});

app.use('/graphql', graphqlHTTP({
  schema: schema,
  graphiql: process.env.NODE_ENV !== 'production',
  customFormatErrorFn: (error) => {
    console.error('GraphQL Error:', error.message);
    return {
      message: error.message,
      locations: error.locations,
      path: error.path
    };
  },
  validationRules: [
    depthLimit(5),
    createComplexityLimitRule(1000, {
      onCost: (cost) => {
        console.log('Query cost:', cost);
      }
    })
  ]
}));

const PORT = parseInt(process.env.PORT || '4000', 10);

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

process.on('SIGTERM', async () => {
  await pool.end();
  process.exit(0);
});